import socket
import threading
import json
import time
import math

class GameServer:
    def __init__(self, host='127.0.0.1', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((host, port))
        self.clients = {}
        self.game_state = {}
        self.running = True
    
    def start(self):
        threading.Thread(target=self.listen_for_clients, daemon=True).start()
        threading.Thread(target=self.update_game_state, daemon=True).start()
        self.broadcast_game_state()

    def listen_for_clients(self):
        while self.running:
            data, addr = self.server_socket.recvfrom(1024)
            if addr not in self.clients:
                self.clients[addr] = {'position': [0, 0], 'id': len(self.clients)}
            command = json.loads(data.decode())
            if command['action'] == 'update_position':
                self.clients[addr]['position'] = command['position']
    
    def update_game_state(self):
        while self.running:
            self.game_state = {addr: client for addr, client in self.clients.items()}
            time.sleep(1)

    def broadcast_game_state(self):
        while self.running:
            game_state_msg = json.dumps(self.game_state).encode()
            for client in self.clients.keys():
                self.server_socket.sendto(game_state_msg, client)
            time.sleep(1)

    def calculate_distance(self, pos1, pos2):
        return math.sqrt((pos1[0] - pos2[0]) ** 2 + (pos1[1] - pos2[1]) ** 2)

    def stop(self):
        self.running = False
        self.server_socket.close()

if __name__ == "__main__":
    server = GameServer()
    server.start()